css:
.loader {
  width: 50px;
  aspect-ratio: 1;
  background: linear-gradient(#ed303c 0 0), linear-gradient(#3b8183 0 0), linear-gradient(#ff9c5b 0 0) #ed303c;
  background-position: center;
  background-repeat: no-repeat;
  animation: l12 2s infinite;
}
@keyframes l12 {
  0% { background-size: 100% 100%, 100% 100%, 100% 100%; }
  33% { background-size: 0 0, 100% 100%, 100% 100%; }
  66% { background-size: 0 0, 0 0, 100% 100%; }
  100% { background-size: 0 0, 0 0, 0 0; }
}
